const generateQuoteNumber = () => {
  const num = Math.floor(Math.random() * 400) + 100;
  const year = new Date().getFullYear();
  return `ALC-${year}-${num}`;
};

const todayFormatted = () => {
  return new Date().toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
};

const todayISO = () => {
  return new Date().toISOString().split("T")[0];
};

const formatMoney = (val) => {
  const num = parseFloat(val);
  if (isNaN(num)) return "$0.00";
  return "$" + num.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
};

const escapeHtml = (str) => {
  if (!str) return "";
  return String(str).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
};

const calculateTotals = (items, discounts = []) => {
  const filteredItems = items.filter((i) => i.description);
  const filteredDiscounts = discounts.filter((d) => d.description && d.amount);
  const subtotal = filteredItems.reduce((sum, item) => sum + (item.qty || 0) * (item.unitPrice || 0), 0);
  const discountTotal = filteredDiscounts.reduce((sum, d) => sum + (d.amount || 0), 0);
  const total = Math.max(0, subtotal - discountTotal);
  return { filteredItems, filteredDiscounts, subtotal, discountTotal, total };
};

