  // Fetch customers from Supabase
  useEffect(() => {
    async function loadCustomers() {
      try {
        const { data, error } = await supabase
          .from("customers")
          .select("id, name, property_address, property_city, property_state, property_zip, phone, email")
          .is("deleted_at", null)
          .order("name", { ascending: true });
        if (error) { console.error("Failed to load customers:", error); return; }
        if (data) setCustomers(data);
      } catch (err) {
        console.error("Customer fetch error:", err);
      }
    }
    loadCustomers();
  }, []);

  const handleCustomerSelect = (customerId) => {
    setSelectedCustomerId(customerId);
    if (customerId === "" || customerId === "new") {
      if (customerId === "new") {
        setCustomerName("");
        setCustomerAddress("");
      }
      return;
    }
    const c = customers.find((cust) => cust.id === customerId);
    if (c) {
      setCustomerName(c.name);
      const parts = [c.property_address];
      if (c.property_city) parts.push(c.property_city);
      if (c.property_state) parts.push(c.property_state);
      if (c.property_zip) parts.push(c.property_zip);
      setCustomerAddress(parts.join(", "));
    }
  };

  const addItem = () => {
    setItems([...items, { description: "", qty: 1, unitPrice: 0 }]);
  };

  const removeItem = (index) => {
    if (items.length > 1) {
      setItems(items.filter((_, i) => i !== index));
    }
  };

  const updateItem = (index, field, value) => {
    const updated = [...items];
    if (field === "qty" || field === "unitPrice") {
      updated[index][field] = value === "" ? "" : parseFloat(value) || 0;
    } else {
      updated[index][field] = value;
    }
    setItems(updated);
  };

  const nextDiscountId = useRef(0);

  const addDiscount = () => {
    setDiscounts([...discounts, { id: nextDiscountId.current++, description: "", amount: "" }]);
  };

